// Filter today's scheduled posts
const today = new Date().toISOString().split('T')[0];
const items = $input.all();
const todayPosts = items.filter(item => {
  const postDate = item.json.date?.split('T')[0];
  return postDate === today;
});

// Also get upcoming 3 days
const upcoming = items.filter(item => {
  const postDate = new Date(item.json.date);
  const now = new Date();
  const diff = (postDate - now) / (1000 * 60 * 60 * 24);
  return diff > 0 && diff <= 3;
});

return [{
  json: {
    today: todayPosts.map(p => p.json),
    upcoming: upcoming.map(p => p.json),
    today_count: todayPosts.length,
    upcoming_count: upcoming.length
  }
}];
